   771→// ─── Intent classifier ────────────────────────────────────────────────────────
   772→
   773→function classify(message) {
   774→  const m = message.toLowerCase();
   775→  if (/overdue/.test(m))                                                                        return 'overdue';
   776→  if (/budget/.test(m))                                                                         return 'budget';
   777→  if (/\brams\b|\bram\b|method statement|risk assessment/.test(m))                             return 'rams';
   778→  if (/\bcis\b|cis return|cis returns|construction industry scheme|deduction/.test(m))         return 'cis';
   779→  if (/daily report|daily reports|site diary|progress report/.test(m))                         return 'daily_reports';
   780→  if (/risk register|hazard register|\brisk\b|\brisks\b/.test(m))                              return 'risk';
   781→  if (/change order|change orders|variation|variations|\bco\b|\bvo\b/.test(m))                 return 'change_orders';
   782→  if (/purchase order|purchase orders|\bprocurement\b|supplier order/.test(m))                 return 'purchase_orders';
   783→  if (/\bpo\b/.test(m))                                                                         return 'purchase_orders';
   784→  if (/subcontractor|subcontractors|subbies|\bcontractor\b|sub-contractor/.test(m))            return 'subcontractors';
   785→  if (/\bequipment\b|\bplant\b|machinery|\bcrane\b|excavator|\bvehicle\b|\bhire\b/.test(m))    return 'equipment';
   786→  if (/\bmaterial\b|\bmaterials\b|\bsupplies\b|\bdelivery\b|\bstock\b/.test(m))                return 'materials';
   787→  if (/timesheet|timesheets|\bhours\b|\bpayroll\b|overtime/.test(m))                           return 'timesheets';
   788→  if (/\bcontact\b|\bcontacts\b|\bclient\b|\bclients\b|\bcrm\b|prospect/.test(m))              return 'contacts';
   789→  if (/project/.test(m))                                                                        return 'projects';
   790→  if (/invoice|invoices|payment|payments|cash/.test(m))                                        return 'invoices';
   791→  if (/safety|incident|hazard|near.?miss|accident/.test(m))                                    return 'safety';
   792→  if (/team|worker|staff|member|employee/.test(m))                                             return 'team';
   793→  if (/\brfi\b|rfis/.test(m))                                                                   return 'rfis';
   794→  if (/tender|bid|bidding|pipeline/.test(m))                                                   return 'tenders';
   795→  return 'unknown';
   796→}
   797→
   798→// ─── POST /chat ───────────────────────────────────────────────────────────────
   799→
   800→router.post('/chat', async (req, res) => {
   801→  const { message, context } = req.body;
   802→
   803→  if (!message || typeof message !== 'string' || !message.trim()) {
   804→    return res.status(400).json({ message: 'message is required' });
   805→  }
   806→
   807→  try {
   808→    const intent = classify(message.trim());
   809→    let result;
   810→
   811→    switch (intent) {
   812→      case 'projects':        result = await handleProjects();        break;
   813→      case 'invoices':        result = await handleInvoices();        break;
   814→      case 'overdue':         result = await handleOverdue();         break;
   815→      case 'safety':          result = await handleSafety();          break;
   816→      case 'team':            result = await handleTeam();            break;
   817→      case 'rfis':            result = await handleRfis();            break;
   818→      case 'tenders':         result = await handleTenders();         break;
   819→      case 'budget':          result = await handleBudget();          break;
   820→      case 'materials':       result = await handleMaterials();       break;
   821→      case 'timesheets':      result = await handleTimesheets();      break;
   822→      case 'subcontractors':  result = await handleSubcontractors();  break;
   823→      case 'equipment':       result = await handleEquipment();       break;
   824→      case 'change_orders':   result = await handleChangeOrders();    break;
   825→      case 'purchase_orders': result = await handlePurchaseOrders();  break;
   826→      case 'contacts':        result = await handleContacts();        break;
   827→      case 'rams':            result = await handleRams();            break;
   828→      case 'cis':             result = await handleCIS();             break;
   829→      case 'daily_reports':   result = await handleDailyReports();    break;
   830→      case 'risk':            result = await handleRisk();            break;
   831→      default:                result = handleUnknown(message.trim()); break;
   832→    }
   833→
   834→    res.json({
   835→      reply:       result.reply,
   836→      data:        result.data ?? null,
   837→      suggestions: result.suggestions,
   838→    });
   839→  } catch (err) {
   840→    console.error('[AI /chat]', err.message);
   841→    res.status(500).json({ message: 'AI assistant encountered an error: ' + err.message });
   842→  }
   843→});
   844→
   845→module.exports = router;
